        has_parking = False
        bp_val = None
        pk_val = None

        if isinstance(attrs, dict):
            # Bike
            if 'BikeParking' in attrs:
                bp_val = attrs['BikeParking']
                if bp_val == 'True':
                    has_bike = True

            # Parking
            if 'BusinessParking' in attrs:
                pk_str = attrs['BusinessParking']
                pk_val = pk_str
                if pk_str and pk_str != 'None':
                    try:
                        pk_dict = ast.literal_eval(pk_str)
                        if isinstance(pk_dict, dict):
                            if any(pk_dict.values()):
                                has_parking = True
                    except:
                        pass

        if has_bike or has_parking:
            matches += 1

        # Add to debug info (limit to first 10 to avoid huge output)
        if len(debug_info) < 10:
            debug_info.append({
                "bid": bid,
                "attrs": attrs,
                "has_bike": has_bike,
                "has_parking": has_parking,
                "bp_val": bp_val,
                "pk_val": pk_val
            })

result = {
    "count": matches,
    "debug_sample": debug_info,
    "total_targets": len(target_ids)
}

print("__RESULT__:")
print(json.dumps(result))

